lf))return 0 end;function CapsValue:GetVarName()if self.type==CapsValue.EValueType._var then return tostring(self.value)end;LogTool.Info("语法错误200006, 不是变量: "..self.__tostring(self))return''end;function CapsValue:GetItem(e)if self.type~=CapsValue.EValueType._list then LogTool.Info("语法错误200010, GetItem不是数组: "..self.__tostring(self))return nil end;if e<1 or e>#self.value then LogTool.Info("语法错误200011, GetItem中出现了错误的index: "..self.__tostring(self))return nil end;return self.value[e]end;function CapsValue:GetLength()if self.type~=CapsValue.EValueType._list then LogTool.Info("语法错误200013, GetLength不是数组: "..self.__tostring(self))return 0 end;return#self.value end;function CapsValue:AddItem(f)if self.type~=CapsValue.EValueType._list then LogTool.Info("语法错误200014, AddItem不是数组:"..self.__tostring(self))return end;table.insert(self.value,f)end;function CapsValue:Insert(e,f)if self.type~=CapsValue.EValueType._list then LogTool.Info("语法错误200018, Insert不是数组:"..self.__tostring(self))return end;table.insert(self.value,e,f)end;function CapsValue:RemoveAt(e)if self.type~=CapsValue.EValueType._list then LogTool.Info("语法错误200015, RemoveAt不是数组:"..self.__tostring(self))return end;if e<1 or e>#self.value then LogTool.Info("语法错误200016, RemoveAt中出现了错误的index:"..self.__tostring(self))return end;table.remove(self.value,e)end;function CapsValue:Equal(g)if g==nil then return false end;if self.type~=g.type then return false end;if self.type==CapsValue.EValueType.number then return tonumber(self.value)==tonumber(g.value)elseif self.type==CapsValue.EValueType._bool then return d(self.value)==d(g.value)elseif self.type==CapsValue.EValueType.str then return tostring(self.value)==tostring(g.value)end;return false end;function CapsValue:BiggerThan(g)if g==nil then LogTool.Info('运行错误10000, null不能比较大小')return false end;if self.type~=CapsValue.EValueType.number or g.type~=CapsValue.EValueType.number then LogTool.Info('运行错误10001, 两个非数字之间不能比较大小')return false end;return tonumber(self.value)>tonumber(g.value)en